 1	import { type FC, useMemo } from 'react';
 2	
 3	import { ProviderModel, ProviderModelGroupVersionKind, type V1beta1Provider } from '@kubev2v/types';
 4	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 5	
 6	import { loadUserSettings } from '../../components/common/Page/userSettings';
 7	import StandardPage from '../../components/page/StandardPage';
 8	import useGetDeleteAndEditAccessReview from '../../modules/Providers/hooks/useGetDeleteAndEditAccessReview';
 9	import type { ProviderData } from '../../modules/Providers/utils/types/ProviderData';
10	import InventoryNotReachable from '../../modules/Providers/views/list/components/InventoryNotReachable';
11	import { useForkliftTranslation } from '../../utils/i18n';
12	import ProvidersAddButton from '../list/components/ProvidersAddButton';
13	import { findInventoryByID } from '../list/utils/findInventoryByID';
14	
15	import ProviderRow from './components/ProviderRow';
16	import ProvidersEmptyState from './components/ProvidersEmptyState';
17	import useProvidersInventoryList from './hooks/useProvidersInventoryList';
18	import { providerFields } from './utils/providerFields';
19	
20	import './ProvidersListPage.style.css';
21	
22	const ProvidersListPage: FC<{
23	  namespace: string;
24	}> = ({ namespace }) => {
25	  const { t } = useForkliftTranslation();
26	
27	  const userSettings = useMemo(() => loadUserSettings({ pageId: 'Providers' }), []);
28	
29	  const [providers, providersLoaded, providersLoadError] = useK8sWatchResource<V1beta1Provider[]>({
30	    groupVersionKind: ProviderModelGroupVersionKind,
31	    isList: true,
32	    namespace,
33	    namespaced: true,
34	  });
35	
36	  const {
37	    error: inventoryError,
38	    inventory,
39	    loading: inventoryLoading,
40	  } = useProvidersInventoryList(namespace);
41	
42	  const permissions = useGetDeleteAndEditAccessReview({
43	    model: ProviderModel,
44	    namespace,
45	  });
46	
47	  const data: ProviderData[] = useMemo(
48	    () =>
49	      (providers ?? []).map((provider) => ({
50	        inventory: findInventoryByID(inventory, provider.metadata?.uid),
51	        permissions,
52	        provider,
53	      })),
54	    [providers, inventory, permissions],
55	  );
56	
57	  return (
58	    <StandardPage<ProviderData>
59	      data-testid="providers-list"
60	      addButton={
61	        <ProvidersAddButton
62	          testId="add-provider-button"
63	          namespace={namespace}
64	          canCreate={permissions.canCreate}
65	        />
66	      }
67	      dataSource={[data || [], providersLoaded, providersLoadError]}
68	      RowMapper={ProviderRow}
69	      fieldsMetadata={providerFields}
70	      namespace={namespace}
71	      title={t('Providers')}
72	      titleHelpContent={t(
73	        'Providers refer to environments where the virtual machines originate from or are moved to during the migration process.',
74	      )}
75	      userSettings={userSettings}
76	      alerts={
77	        !inventoryLoading && inventoryError
78	          ? [<InventoryNotReachable key={'inventoryNotReachable'} />]
79	          : undefined
80	      }
81	      customNoResultsFound={
82	        <ProvidersEmptyState namespace={namespace} canCreate={permissions.canCreate} />
83	      }
84	      page={1}
85	    />
86	  );
87	};
88	
89	export default ProvidersListPage;

